import{_ as a,c as e,a as n,o as i}from"./app-CEcM0piI.js";const l={};function p(t,s){return i(),e("div",null,s[0]||(s[0]=[n(`<p>Webpack是一个静态资源打包工具。 它会以一个或多个文件作为打包的入口，将我们整个项目所有文件编译组合成一个或多个文件输出出去。 输出的文件就是编译好的文件，就可以在浏览器段运行了。 我们将Webpack输出的文件叫做bundle。</p><p><code>webpack</code>命令用于打包项目</p><p>webpack是基于nodejs平台的，因此规范是CommonJS规范</p><h2 id="模式" tabindex="-1"><a class="header-anchor" href="#模式"><span>模式</span></a></h2><ul><li>开发模式：仅能编译JS中的ESModule语法</li><li>生产模式：能编译JS中的ESModule语法，还能压缩JS代码</li></ul><h1 id="配置" tabindex="-1"><a class="header-anchor" href="#配置"><span>配置</span></a></h1><p><strong>五大基础配置</strong></p><ol><li>entry (入口) 指示Webpack从哪个文件开始打包</li><li>output （输出） 指示Webpack打包完的文件输出到哪里去，如何命名等</li><li>loader（加载器） webpack本身只能处理js、json等资源，其他资源需要借助loader，Webpack才能解析</li><li>plugins (插件) 扩展Webpack的功能</li><li>mode (模式） 主要由两种模式：</li></ol><ul><li>开发模式：development</li><li>生产模式：production</li></ul><h2 id="output" tabindex="-1"><a class="header-anchor" href="#output"><span>output</span></a></h2><table><thead><tr><th>属性</th><th>作用</th></tr></thead><tbody><tr><td>path</td><td>输出目录（从磁盘根目录开始）</td></tr><tr><td>filename</td><td>入口文件输出文件名，也可以包含目录</td></tr><tr><td>clean</td><td>是否清除输出目录中原有的文件</td></tr><tr><td>chunkFilename</td><td>除入口文件的打包输出的其他文件命名</td></tr><tr><td>assetModuleFilename</td><td>图片，字体等通过asset处理的资源统一命名方式</td></tr></tbody></table><h2 id="loader" tabindex="-1"><a class="header-anchor" href="#loader"><span>loader</span></a></h2><table><thead><tr><th>属性</th><th>作用</th></tr></thead><tbody><tr><td>test</td><td>设定正则的方式匹配要处理的文件</td></tr><tr><td>loader</td><td>指定处理器（只能使用一个）</td></tr><tr><td>use</td><td>指定处理器（可以使用多个，以数组的方式），多个处理器按从后往前的顺序执行</td></tr></tbody></table><h3 id="图片处理" tabindex="-1"><a class="header-anchor" href="#图片处理"><span>图片处理</span></a></h3><p>过去在Webpack4时，我们处理图片资源通过file-loader和url-loader进行处理 现在Webpack5已经将两个Loader功能内置到Webpack里了，我们只需要简单配置即可处理图片资源</p><p>在处理图片时通常将图片转换成base64格式传输（字符串形式） 优势就是就是减少请求数量减轻服务器压力 缺点是转换后体积会变大。图片体积越大增加的也越大，因此通常将小尺寸图片处理成base64</p><ul><li>asset：webpack自带的文件和url处理器，会根据dataUrlCondition转base64</li><li>paser：解析配置 <ul><li>dataUrlCondition：该配置生效条件</li><li>maxSize：文件最大大小</li><li>genertaor：配置生成结果 <ul><li>filename：指定文件名，也可以同时在里面指定生成目录</li></ul></li></ul></li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>	test: /\\.(jpe?g|png|gif|webp|svg)$/i,</span></span>
<span class="line"><span>	type:&#39;asset&#39;,</span></span>
<span class="line"><span>    parser: {</span></span>
<span class="line"><span>        dataUrlCondition: {</span></span>
<span class="line"><span>	         maxSize: 10 * 1024, //10kb</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>},</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="文字处理" tabindex="-1"><a class="header-anchor" href="#文字处理"><span>文字处理</span></a></h4><p>文字处理不需要转base64因此使用asset下的resource</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>	 test: /\\.(ttf|woff2?|mp3|mp4)$/,</span></span>
<span class="line"><span>     type: &quot;asset/resource&quot;,</span></span>
<span class="line"><span>     generator: {</span></span>
<span class="line"><span>        filename: &quot;static/font/[hash:8][query][name].[ext]&quot;,</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>},</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>音视频等不需要额外处理的资源也是通过asset下的resource处理</p><h2 id="plugins" tabindex="-1"><a class="header-anchor" href="#plugins"><span>plugins</span></a></h2><p>插件需要先导入后再注册的，配置需要在注册时传入到注册的对象中</p><p>eslint需要使用插件引入eslint-webpack-plugin</p><p>处理html需要插件引入html-webpack-plugin</p><h1 id="开发服务器" tabindex="-1"><a class="header-anchor" href="#开发服务器"><span>开发服务器</span></a></h1><p>使用开发服务器可以实现自动化打包 <strong>开发服务器是在内存中编译打包的，因此在磁盘中看不到打包的文件</strong></p><p>使用webpack-dev-server的npm库可以实现监视项目自动打包 需要在plugin中配置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>devServer：{</span></span>
<span class="line"><span>	host:&#39;localhost&#39;, //启动服务器域名</span></span>
<span class="line"><span>	port:&#39;3000&#39;, //启动服务器端口号</span></span>
<span class="line"><span>	open:true, //是否自动打开浏览器</span></span>
<span class="line"><span>	hot:true, //热替换</span></span>
<span class="line"><span>	devMiddleware: {</span></span>
<span class="line"><span>	    writeToDisk: true,</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>接着执行<code>npx webpack server</code>就可以实现监听了</p><p>普通的打包重新打包是把所有内容都打包 开启热替换只重新打包更改部分的代码</p><p>热替换只对html和css生效 要js实现热替换需要配置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>if(module.hot){//判断是否支持热替换功能</span></span>
<span class="line"><span>	module.hot.accept(&#39;文件路径+文件名&#39;)//对指定js文件开启热替换</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="生产模式" tabindex="-1"><a class="header-anchor" href="#生产模式"><span>生产模式</span></a></h2><h3 id="打包单独的css文件" tabindex="-1"><a class="header-anchor" href="#打包单独的css文件"><span>打包单独的css文件</span></a></h3><p>正常的打包会把css文件打包到js中，这样打包的结构就是浏览器解析js文件后会把里面的css代码插入到html中 如果在网速慢的情况下会出现闪屏的现象，即html加载完成后要等待浏览器解析完js后再插入css代码</p><p>可以使用mini-css-extract-plugin插件 这个插件是替代style-loader的 虽然是个插件，但是提供的是loader，需要在loader中配置，同时也需要在插件中注册 此插件中的loader与其他loader不同，它引入时不需要使用字符串的方式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>	test:/\\.css$/,</span></span>
<span class="line"><span>	use:[MiniCssExtratPlugin.loader,&quot;css-loader&quot;]</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="兼容性处理" tabindex="-1"><a class="header-anchor" href="#兼容性处理"><span>兼容性处理</span></a></h3><p>css中也是存在兼容性问题的 需要使用postcss-loader处理 postcss-loader在使用时需要放在less，sass等loader的后面，css-loader的前面 同时还需要进行配置 如果只在webpack的配置文件中配置也不会其效果，它是根据package.json中关于浏览器兼容配置来决定程度的</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>	test:/\\.less$/,</span></span>
<span class="line"><span>	use:[</span></span>
<span class="line"><span>		MiniCssExtractPlugin.loader,</span></span>
<span class="line"><span>		&quot;css-loader&quot;,</span></span>
<span class="line"><span>		{</span></span>
<span class="line"><span>			loader:&quot;postcss-loader&quot;,</span></span>
<span class="line"><span>			options:{</span></span>
<span class="line"><span>				postcssOptions:{</span></span>
<span class="line"><span>					plugins:[</span></span>
<span class="line"><span>						&quot;postcss-preset-env&quot;,//能解决大多数样式兼容性问题</span></span>
<span class="line"><span>					]</span></span>
<span class="line"><span>				}</span></span>
<span class="line"><span>			}	</span></span>
<span class="line"><span>		},</span></span>
<span class="line"><span>		sass-loader&quot;,//将sass编译成css文件</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h3 id="css压缩" tabindex="-1"><a class="header-anchor" href="#css压缩"><span>css压缩</span></a></h3><p>在生产环境中html和js代码都可以自动被压缩 但css压缩需要使用插件CssMinimizerPlugin</p><h2 id="sourcemap" tabindex="-1"><a class="header-anchor" href="#sourcemap"><span>SourceMap</span></a></h2><p>源代码映射是一个用来生成源代码与构建后代码一一映射的文件的方案。</p><p>浏览器上运行的代码是构建后的代码，报错的位置是编译后的位置 使用源码映射可以将报错的地方显示在源代码中</p><p>它会生成一个xxx.ma文件，里面包含源代码和构建后代码每一行、每一列的映射关系。当构建后代码出错了，会通过xxx.map文件，从构建后代码出错位置找到映射后源代码出错位置，从而让浏览器提示源代码文件出错位置，帮助我们更快的找到错误根源。</p><p>源码映射有多种模式 通常</p><ul><li>开发模式：cheap-module-source-map 打包编译速度快，只包含行映射，没有列映射</li><li>生产模式：source-map 包含行/列映射，打包速度更慢</li></ul><p>在额外的devtool配置中</p><h2 id="loader优化" tabindex="-1"><a class="header-anchor" href="#loader优化"><span>loader优化</span></a></h2><h3 id="oneof" tabindex="-1"><a class="header-anchor" href="#oneof"><span>oneOf</span></a></h3><p>loader配置原理类似只有if，判断是否符合第一个loader后不管是否执行都会再判断后面的loader 将所有loader添加到oneof中， 每个文件只会执行oneof中的一个loader，处理后oneof后面的loader就不会再执行了</p><h3 id="include-exclude" tabindex="-1"><a class="header-anchor" href="#include-exclude"><span>include/exclude</span></a></h3><p>排除或包含某文件/文件夹 这两个配置只能写一个</p><h3 id="缓存" tabindex="-1"><a class="header-anchor" href="#缓存"><span>缓存</span></a></h3><p>占时间的处理通常是js文件</p><p><strong>对bable开启缓存</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>options:{</span></span>
<span class="line"><span>	cacheDirectory:true, //开启缓存</span></span>
<span class="line"><span>	cacheCompression: false, //关闭缓存文件压缩</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>对eslint开启缓存</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cache:true, //开启缓存</span></span>
<span class="line"><span>cacheLocation:path.resolvbe(__dirname,&#39;node_modules/&#39;) //缓存路径</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="多线程打包" tabindex="-1"><a class="header-anchor" href="#多线程打包"><span>多线程打包</span></a></h2><p>当项目越来越庞大时，打包速度越来越慢，甚至于需要一个下午才能打包出来代码。这个速度是比较慢的。 我们想要继续提升打包速度，其实就是要提升js的打包速度，因为其他文件都比较少。 而对js文件处理主要就是eslint、babel、lerser三个工具，所以我们要提升它们的运行速度。 我们可以开启多进程同时处理js文件，这样速度就比之前的单进程打包更快了。</p><p>多线程loader处理需要在对应的loader后面添加thread-loader</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>    test: /\\.js$/ ,</span></span>
<span class="line"><span>    exclude: &quot;/node_modules/&quot;,</span></span>
<span class="line"><span>    include: path.resolve(__dirname,&quot;../src&quot;),//只处理src下的文件,其他文件不处理</span></span>
<span class="line"><span>	use:[</span></span>
<span class="line"><span>		{</span></span>
<span class="line"><span>			loader：&quot;thread-loader&quot;，//开启多进程</span></span>
<span class="line"><span>			options:{</span></span>
<span class="line"><span>				works:threads，// 进程数量</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		},</span></span>
<span class="line"><span>		{</span></span>
<span class="line"><span>			loader:&quot;babel-loader&quot;,</span></span>
<span class="line"><span>			options:{</span></span>
<span class="line"><span>				// presets:[&quot;@babel/preset-env&quot;],</span></span>
<span class="line"><span>				cacheDirectory：true，//开启babel缓存</span></span>
<span class="line"><span>				cacheCompression：false，//关闭缓存文件压缩</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="图片压缩" tabindex="-1"><a class="header-anchor" href="#图片压缩"><span>图片压缩</span></a></h2><p>image-minimizer-webpack-plugin插件进行压缩。压缩静态图片 此外还需要下载对应的无损压缩和有损压缩插件</p><h2 id="代码分割" tabindex="-1"><a class="header-anchor" href="#代码分割"><span>代码分割</span></a></h2><p>将打包生成的文件进行代码分割，生成多个js文件，谊染哪个页面就只加载某个js文件，这样加载的资源就少，速度就更快。 代码分割（CodeSplit）主要做了两件事：</p><ol><li>分割文件：将打包生成的文件进行分割，生成多个js文件。</li><li>按需加载：需要哪个文件就加载哪个文件。</li></ol><p>设置多个入口，打包时只会打包与入口有关的代码，也就实现了代码分割</p><p>多个分割块如果复用了公共代码，那么公共代码也会打包多份 可以配置公共代码只打包一份</p><h2 id="按需加载" tabindex="-1"><a class="header-anchor" href="#按需加载"><span>按需加载</span></a></h2><p>将页面暂时用不到的代码进行懒加载，将资源优先给页面当前用得上的资源加载</p><p>按需加载不是webpack中的，是在js中使用动态导入 如：按钮点击时动态加载</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>btn.onClick+=()=&gt;{</span></span>
<span class="line"><span>	import(&#39;./test&#39;)</span></span>
<span class="line"><span>	console.log(&#39;加载test模块&#39;)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="preload-prefetch" tabindex="-1"><a class="header-anchor" href="#preload-prefetch"><span>preload/prefetch</span></a></h3><p>按需加载如果资源体积很大，那么用户会感觉到明显卡顿效果。</p><ul><li>Preload：告诉浏览器立即加载资源。</li><li>Prefetch：告诉浏览器在空闲时才开始加载资源。</li></ul><p>它们共同点： 都只会加载资源，并不执行。 都有缓存。</p><p>当前页面优先级高的资源用Preload加载 下一个页面需要使用的资源使用Prefetch加载</p><p>但兼容性比较差</p><p>但大多数实现都停止了维护，所以使用vue官方开发的（并不需要vue全部项目）</p><h2 id="networkcache" tabindex="-1"><a class="header-anchor" href="#networkcache"><span>NetworkCache</span></a></h2><p>一个文件引入了另一个文件，在打包后它们命名会有所改变也就是哈希值命名变化哈希值变化，这样一个文件改变后他的哈希值命名也改变，引入它的文件中也要发生改变，这样会导致多个相互引用的文件都会发生改变，这些都要重新编译</p><p>使用runtimeChunk将文件名和文件哈希值名映射在一个文件中，当文件发生更改时它所映射的文件中的名字依旧不会更改</p><h1 id="core-js" tabindex="-1"><a class="header-anchor" href="#core-js"><span>core-js</span></a></h1><p>bable也有一些内容无法处理，如：async，await，promise等 这样依旧会有兼容性问题</p><p>core-js是专门用来做ES6以及以上API的polyfill。</p><p><strong>手动引入</strong> core-js就是一个库，在需要的js文件中引入需要的模块即可</p><p><strong>自动引入</strong> 在babel中有core-js的插件，可以在babel中配置core-js的自动引入</p><h1 id="pwa" tabindex="-1"><a class="header-anchor" href="#pwa"><span>pwa</span></a></h1><p>渐进式网络应用程序(progressivewebapplication-PWA)：是一种可以提供类似于nativeapp(原生应用程序)体验的WebApp的技术。 其中最重要的是，在离线（offline)时应用程序能够继续运行功能。 内部通过ServiceWorkers技术实现的。</p><p>下载后需要在js文件中注册后才能使用 一般在main.js中注册，只注册一次即可</p><h1 id="loader-1" tabindex="-1"><a class="header-anchor" href="#loader-1"><span>loader</span></a></h1><p>帮助webpack将不同类型的文件转换为webpack可识别的模块。</p><p>按执行顺序分类：</p><ul><li>pre:前置loader</li><li>normal:普通loader</li><li>inline：内联loader</li><li>post:后置loader</li></ul><p>执行顺序为pre&gt;normal&gt;inline&gt;post 相同优先级的loader的执行顺序为从右到左，从下到上</p><p>定义loader的优先级使用enforce指定是哪个类型，如果不指定默认是normal</p><h3 id="使用方式" tabindex="-1"><a class="header-anchor" href="#使用方式"><span>使用方式</span></a></h3><ol><li>配置方式：在webpack.config.js文件中指定loader。（pre、normal、post loader)</li><li>内联方式：在每个import语句中显式指定loader。（inlineloader)</li></ol><p><strong>inline loader</strong> 使用css-loader和style-loader处理styles.css文件 通过！将资源中的loader分开</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import Styles from&#39;style-loader!css-loader?modules!./styles.css&#39;;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>！跳过normal loader</li><li>-！跳过pre和normal loader</li><li>！！ 跳过pre，normal，post loader</li></ul><p>loader就是一个函数 当webpack解析资源时，会调用相应的loader去处理 loader接受到文件内容作为参数，返回内容出去</p><ul><li>content： 文件内容</li><li>map： SourceMap</li><li>meta： 给下一个loader传递的数据</li></ul><div class="language-my-loader.js line-numbers-mode" data-highlighter="shiki" data-ext="my-loader.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports=function(content,map,meta){</span></span>
<span class="line"><span>	console.log(content)</span></span>
<span class="line"><span>	return content</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="同步loader" tabindex="-1"><a class="header-anchor" href="#同步loader"><span>同步loader</span></a></h4><p>普通声明的函数就是一个同步loader</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports=function(content,map,meta){</span></span>
<span class="line"><span>	console.log(content)</span></span>
<span class="line"><span>	return context</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用callback调用的也是同步loader 比普通的在调用callback时多传入的第一个参数是err表示是否有错误</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports=function(context,map,meta){</span></span>
<span class="line"><span>	this.callback(null,content,map,meta)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>同步loader中不能执行异步操作</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports=function(context,map,meta){</span></span>
<span class="line"><span>	console.log(&quot;test1&quot;)</span></span>
<span class="line"><span>	setTimeout(()=&gt;{</span></span>
<span class="line"><span>		console.log(&quot;test1&quot;)</span></span>
<span class="line"><span>		this.callback(null,content,map,meta)</span></span>
<span class="line"><span>	},1000)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>会报错</p><h4 id="异步loader" tabindex="-1"><a class="header-anchor" href="#异步loader"><span>异步loader</span></a></h4><p>使用async调用的loader是异步loader</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports=function(context,map,meta){</span></span>
<span class="line"><span>	const callback=this.async()</span></span>
<span class="line"><span>	setTimeout(()=&gt;{</span></span>
<span class="line"><span>		console.log(&quot;test1&quot;)</span></span>
<span class="line"><span>		this.callback(null,content,map,meta)</span></span>
<span class="line"><span>	},1000)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="raw-loader" tabindex="-1"><a class="header-anchor" href="#raw-loader"><span>raw loader</span></a></h4><p>raw loader接收到的是buffer数据（二进制） 要使用raw loader只需要将函数的raw指定出来即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports=function(content){</span></span>
<span class="line"><span>	console.log(content) //二进制数据</span></span>
<span class="line"><span>	return content</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>module.exports.raw=true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>raw loader用于处理文件如图片等</p><h4 id="pitch-loader" tabindex="-1"><a class="header-anchor" href="#pitch-loader"><span>pitch loader</span></a></h4><p>pitch loader会抢占执行，多个pitch loader如果不返回结果会先将pitch loader执行完才会执行其他loader 但pitch loader有熔断机制，如果一个pitch loader有返回值那么它后面的pitch loader都不会执行了，直接开始执行其他loader（其他类型的loader不受熔断影响）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>module.exports.pitch=function(){</span></span>
<span class="line"><span>	console.log(&quot;test1&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="api" tabindex="-1"><a class="header-anchor" href="#api"><span>api</span></a></h3><table><thead><tr><th>函数</th><th>作用</th><th>用法</th></tr></thead><tbody><tr><td>this.async</td><td>异步回调loader。返回this.callback</td><td>const callback = this.async0</td></tr><tr><td>this.callback</td><td>可以同步或者异步调用的并返回多个结果的函数</td><td>this.callback(err, content, sourceMap?, meta?)</td></tr><tr><td>this.getOptions(schema)</td><td>获取loader的options，需要对schema写规则</td><td>this.getOptions(schema)</td></tr><tr><td>this.emitFile</td><td>产生一个文件</td><td>this.emitFile(name, content, sourceMap)</td></tr><tr><td>this.utils.contextify</td><td>返回一个相对路径</td><td>this.utils.contextify(context, request)</td></tr><tr><td>this.utils.absolutify</td><td>返回一个绝对路径</td><td>this.utils.absolutify(context, request)</td></tr></tbody></table><h1 id="plugin" tabindex="-1"><a class="header-anchor" href="#plugin"><span>plugin</span></a></h1><p>通过插件我们可以扩展webpack，加入自定义的构建行为，使webpack可以执行更广泛的任务，拥有更强的构建能力。</p><p>站在代码逻辑的角度就是：webpack在编译代码过程中，会触发一系列Tapable钩子事件，插件所做的，就是找到相应的钩子，往上面挂上自己的任务，也就是注册事件，这样，当webpack构建的时候，插件注册的事件就会随着钩子的触发而执行了。</p><p>Tapable为webpack提供了统一的插件接口（钩子）类型定义，它是webpack的核心功能库。webpack中目前有十种hooks，在Tapable源码中可以看到</p><p>Tapable还统一暴露了三个方法给插件，用于注入不同类型的自定义构建行为：</p><ul><li>tap：可以注册同步钩子和异步钩子。</li><li>tapAsync：回调方式注册异步钩子。</li><li>tapPromise：Promise方式注册异步钩子。</li></ul><h2 id="构建对象" tabindex="-1"><a class="header-anchor" href="#构建对象"><span>构建对象</span></a></h2><h3 id="compiler" tabindex="-1"><a class="header-anchor" href="#compiler"><span>Compiler</span></a></h3><p>compiler对象中保存着完整的Webpack环境配置，每次启动webpack构建时它都是一个独一无二，仅仅会创建一次的对象。 这个对象会在首次启动Webpack时创建，我们可以通过compiler对象上访问到Webapck的主环境配置，比如loader、plugin等等配置信息。</p><p>它有以下主要属性：</p><ul><li>compiler.optiors可以访问本次启动webpack时候所有的配置文件，包括但不限于loaders、entry、output、plugin等等完整配置信息。</li><li>compiler.inputFileSystem和compiler.outputFilesystem可以进行文件操作，相当于Nodejs中fs。</li><li>compiler.hooks可以注册tapable的不同种类Hook，从而可以在compiler生命周期中植入不同的逻辑。</li></ul><p>Compilation compilation对象代表一次资源的构建，compilation实例能够访问所有的模块和它们的依赖。 一个compilation对象会对构建依赖图中所有模块，进行编译。在编译阶段，模块会被加载（load）、封存（seal)、优化（optimize)、分块(chunk)、哈希(hash）和重新创建(restore)。</p><p>它有以下主要属性：</p><ul><li>compilation.modules可以访问所有模块，打包的每一个文件都是一个模块。</li><li>compilation.chunkschunk即是多个modules组成而来的一个代码块。入口文件引l入的资源组成一个chunk，通过代码分割的模块又是另外的chunk。</li><li>compilation.assets可以访问本次打包生成所有文件的结果。</li><li>compilation.hooks可以注册tapable的不同种类Hook，用于在compilation编译模块阶段进行逻辑添加以及修改。</li></ul><h1 id="commonjs和esmodel规范" tabindex="-1"><a class="header-anchor" href="#commonjs和esmodel规范"><span>commonjs和esmodel规范</span></a></h1><ul><li>commonjs模块输出的是值的拷贝，es6模块输出的是值的引用</li><li>commonjs模块是运行时加载，es6模块是编译时输出</li><li>commonjs是单个值导出，es6可以导出多个</li><li>CommonJS模块为同步加载，ES6Module支持异步加载</li><li>CommonJS的 this 是当前模块，ES6 Module的 this 是undefined</li></ul><h1 id="webpack原理" tabindex="-1"><a class="header-anchor" href="#webpack原理"><span>webpack原理</span></a></h1><p>![[Pasted image 20250418214013.png]]</p>`,147)]))}const r=a(l,[["render",p]]),c=JSON.parse('{"path":"/front/engineering/1/","title":"1 Webpack","lang":"zh-CN","frontmatter":{"title":"1 Webpack","createTime":"2025/06/22 09:59:48","permalink":"/front/engineering/1/"},"readingTime":{"minutes":13.87,"words":4162},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/工程化/1 Webpack.md","headers":[]}');export{r as comp,c as data};
